#include <iostream>
#include <string>
#include <sstream>
#include <map>
#include <algorithm>
using namespace std;

int main()
{
    string text = "Merhaba dunya bu bir test metni Bu metin kelime sayma icin kullanilacak Merhaba tekrar";

    stringstream ss(text);
    string word;
    map<string, int> wordCount;
    vector<string> words;

    while (ss >> word)
    {
        for (auto& c : word) c = tolower(c);
        words.push_back(word);
        wordCount[word]++;
    }

    cout << "Toplam kelime sayisi: " << words.size() << endl;
    cout << "Toplam karakter sayisi: " << text.length() << endl;

    cout << "\nKelime frekanslari:" << endl;
    for (const auto& entry : wordCount)
    {
        cout << "'" << entry.first << "': " << entry.second << " kez" << endl;
    }

    // En uzun kelime
    string longestWord = words[0];
    for (const string& w : words)
    {
        if (w.length() > longestWord.length())
        {
            longestWord = w;
        }
    }
    cout << "\nEn uzun kelime: '" << longestWord << "' (" << longestWord.length() << " karakter)" << endl;

    // Ortalama kelime uzunlugu
    int totalLength = 0;
    for (const string& w : words) totalLength += w.length();
    double avgLength = (double)totalLength / words.size();
    cout << "Ortalama kelime uzunlugu: " << avgLength << endl;

    return 0;
}
